import{_ as e,o as a,c as r,e as t}from"./app-52052bff.js";const i="/assets/image-be6ca753.png",s="/assets/image-3-459859b2.png",n="/assets/image-1-8d2deccb.png",d="/assets/image-2-33957055.png",h={},o=t('<h2 id="虚拟机栈" tabindex="-1"><a class="header-anchor" href="#虚拟机栈" aria-hidden="true">#</a> 虚拟机栈</h2><h3 id="栈桢" tabindex="-1"><a class="header-anchor" href="#栈桢" aria-hidden="true">#</a> 栈桢</h3><p><img src="'+i+'" alt="Alt text"></p><h3 id="局部变量表" tabindex="-1"><a class="header-anchor" href="#局部变量表" aria-hidden="true">#</a> 局部变量表</h3><h3 id="操作数栈" tabindex="-1"><a class="header-anchor" href="#操作数栈" aria-hidden="true">#</a> 操作数栈</h3><h2 id="垃圾回收" tabindex="-1"><a class="header-anchor" href="#垃圾回收" aria-hidden="true">#</a> 垃圾回收</h2><h3 id="垃圾判断" tabindex="-1"><a class="header-anchor" href="#垃圾判断" aria-hidden="true">#</a> 垃圾判断</h3><h3 id="引用类型" tabindex="-1"><a class="header-anchor" href="#引用类型" aria-hidden="true">#</a> 引用类型</h3><h3 id="垃圾回收算法" tabindex="-1"><a class="header-anchor" href="#垃圾回收算法" aria-hidden="true">#</a> 垃圾回收算法</h3><p><strong>标记-清除算法</strong>：将存活的对象进行标记，然后清理掉未被标记的对象。</p><p>不足：</p><ul><li>标记和清除过程效率都不高</li><li>会产生大量不连续的内存碎片，导致无法给大对象分配内存</li></ul><p><img src="'+s+'" alt="Alt text"></p><p><strong>标记-整理算法</strong>：让所有存活的对象都向一端移动，然后直接清理掉端边界以外的内存</p><p><img src="'+n+'" alt="Alt text"></p><p><strong>复制算法</strong>：将内存划分为大小相等的两块，每次只使用其中一块，当这一块内存用完了就将还存活的对象复制到另一块上面，然后再把使用过的内存空间进行一次清理</p><p>不足：只使用了内存的一半</p><p><img src="'+d+'" alt="Alt text"></p><blockquote><p>现在的商业虚拟机都采用这种收集算法来回收新生代，但是并不是将新生代划分为大小相等的两块，而是分为一块较大的 Eden 空间和两块较小的 Survivor 空间，每次使用 Eden 空间和其中一块 Survivor。在回收时，将 Eden 和 Survivor 中还存活着的对象一次性复制到另一块 Survivor 空间上，最后清理 Eden 和使用过的那一块 Survivor。</p><p>HotSpot 虚拟机的 Eden 和 Survivor 的大小比例默认为 8:1，保证了内存的利用率达到 90%。</p><p>如果每次回收有多于 10% 的对象存活，一块 Survivor 空间就不够用了，此时需要依赖于老年代进行分配担保，也就是借用老年代的空间存储放不下的对象。</p></blockquote><p><strong>分代搜集算法</strong> 现在的商业虚拟机采用分代收集算法，它根据对象存活周期将内存划分为几块，不同块采用适当的收集算法。</p><p>一般将堆分为新生代和老年代。</p><ul><li>新生代使用: 复制算法</li><li>老年代使用: 标记-清除 或者 标记-整理算法</li></ul>',22),c=[o];function p(l,u){return a(),r("div",null,c)}const g=e(h,[["render",p],["__file","JVM.html.vue"]]);export{g as default};
